# Let's systematically parse the family tree and count attendees

print("=== FAMILY TREE ANALYSIS ===")

# Start with the person asking (me)
me = {"name": "Me", "type": "adult", "married": False}

# My parents
mother = {"name": "Mother", "type": "adult", "married": True}
father = {"name": "Father", "type": "adult", "married": True}

# My twin brother's family
twin_brother = {"name": "Twin brother", "type": "adult", "married": True}
twin_brother_spouse = {"name": "Twin brother's spouse", "type": "adult", "married": True}
twin_brother_child1 = {"name": "Twin brother's child 1", "type": "child"}
twin_brother_child2 = {"name": "Twin brother's child 2", "type": "child"}

# My aunt's family
aunt = {"name": "Aunt", "type": "adult", "married": True}
aunt_spouse = {"name": "Aunt's spouse", "type": "adult", "married": True}
aunt_child = {"name": "Aunt's 6-year-old", "type": "child"}

# My grandma and her brother
grandma = {"name": "Grandma", "type": "adult", "married": True}  # widowed but was married
grandma_brother = {"name": "Grandma's brother", "type": "adult", "married": True}  # widowed but was married
# Note: grandpa and grandma's sister-in-law (grandma's brother's wife) passed away

# Grandma's brother's daughter and her family
second_cousin = {"name": "Grandma's brother's daughter (my second cousin)", "type": "adult", "married": True}
second_cousin_spouse = {"name": "Second cousin's spouse", "type": "adult", "married": True}
second_cousin_child1 = {"name": "Second cousin's child 1", "type": "child", "eats_carbs": False}
second_cousin_child2 = {"name": "Second cousin's child 2", "type": "child", "eats_carbs": False}
second_cousin_child3 = {"name": "Second cousin's child 3", "type": "child", "eats_carbs": False}

# Collect all attendees
attendees = [
    me, mother, father,
    twin_brother, twin_brother_spouse, twin_brother_child1, twin_brother_child2,
    aunt, aunt_spouse, aunt_child,
    grandma, grandma_brother,
    second_cousin, second_cousin_spouse, second_cousin_child1, second_cousin_child2, second_cousin_child3
]

print("All attendees:")
for i, person in enumerate(attendees, 1):
    print(f"{i:2d}. {person['name']} ({person['type']})")

adults = [p for p in attendees if p['type'] == 'adult']
children = [p for p in attendees if p['type'] == 'child']

print(f"\nTotals:")
print(f"Adults: {len(adults)}")
print(f"Children: {len(children)}")
print(f"Total attendees: {len(attendees)}")
